import React from 'react';
// import logo from './logo.svg';
import './App.css';
import Dashboard from './components/Dashboard';
import JobSummaryReport from './components/JobSummaryReport';
import User from './components/User';

import {
  Container,
  // Row, Col, Button
} from 'react-bootstrap';

import { DataContext } from './data-context.js';
const util = require('./util.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class App extends React.Component {

  static contextType = DataContext;

  constructor(...args) {
    super(...args);

    // let demoUser = {
    //   _id: "5da1387fe58eb52ac31e0ee2",
    //   code: "3299029",
    //   address: "700/309 หมู่ 6 ต.ดอนหัวฬ่อ อ. เมื่อง จ.ชลบุรี",
    //   division: "MT",
    //   email: "",
    //   name: "วิไล แก้วไกรเพชร์",
    //   note: "",
    //   tel1: "172",
    //   tel2: "086-1509040",
    //   unit: "ME",
    //   isAdmin: true
    // };

    // let defaultTab = demoUser.isAdmin ? '#action/1.1' : '#home';

    // // defaultTab = '#stock/out';  //DEV

    this.state = {
      jobs: [], // TODO load in componentWillMount
      users: [],
      machines: [],
      lines: [],
      // tab: defaultTab,

      // user: demoUser, // DEV
      // user: null,  // PROD
      loadingState: 0, // 100 (4) = machines, 010 (2) = users, 001 (1) = lines, 111 (7) = All
    }

    console.log('process.env.NODE_ENV', process.env.NODE_ENV)
    console.log("React Version:", React.version);
    console.log("API EndPoint:", apiUrl);

    // console.log("Demo User", this.state.user);
  }

  UNSAFE_componentWillMount() {
    let data = this.context.data;
    console.log('JobForm.UNSAFE_componentWillMount')

    util.fetchMachines().then(res => {
      let machines = res.data;
      this.setState({
        machines: machines,
        loadingState: this.state.loadingState | 4
      })
    })

    util.fetchRpUsers().then(res => {
      let users = res.data;
      // console.log('App load users',users)
      this.setState({
        users: users,
        loadingState: this.state.loadingState | 2
      })
    })

    util.fetchLines().then(res => {
      let lines = res.data;


      this.setState({
        lines: lines,
        loadingState: this.state.loadingState | 1
      });
    })

  }

  render() {
    console.log('this.state.loadingState', this.state.loadingState)

    let loading = !(this.state.loadingState === 7);
    return (
      <>
        <DataContext.Provider value={this.state}>
          <Container fluid>
            <Dashboard loading={loading} />
          </Container>
        </DataContext.Provider>

      </>
    );
  }
}
