import React from 'react';
import {
    Container,
    Row, Col,
    Modal,
    Button,
    Form,
    // Table, Pagination, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';
import { css } from '@emotion/core';
import PropTypes from 'prop-types';
// import UserForm from '../forms/UserForm';
// import UserPasswordForm from '../forms/UserPasswordForm';
import GridLoader from 'react-spinners/GridLoader'; // https://www.react-spinners.com/
import { DataContext } from '../data-context';
import ReactDataGrid from "react-data-grid";
import {
    Menu, Data, Filters, Toolbar,
    // ToolsPanel 
} from "react-data-grid-addons";

import {
    FaTrash, FaEdit,
    FaPlus, FaKey,
    // FaTimes, 
    // FaPhoneSquare, FaFax, FaRegEnvelope, 
    // FaAngleLeft, FaAngleRight
} from 'react-icons/fa';

import "./report-styles.css";


const {
    ContextMenu, MenuItem,
    ContextMenuTrigger,
    // SubMenu, 
} = Menu;

const {
    AutoCompleteFilter,
    MultiSelectFilter,
    // NumericFilter,
    // SingleSelectFilter
} = Filters;

const override = css`
    display: block;
    margin: 0 auto;
    border-color: red;
`;

const util = require('../util.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class User extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        data: PropTypes.array,
        loading: PropTypes.bool,
    };


    abortController = new AbortController();
    defaultColumnProperties = {
        filterable: false,
        sortable: true,
        // width: 120
    };
    selectors = Data.Selectors;

    columns = [
        { key: "name", name: "Name", width: 200, filterable: true, filterRenderer: AutoCompleteFilter },
        { key: "code", name: "Code", width: 100, sortDescendingFirst: false, filterable: true, filterRenderer: AutoCompleteFilter, cellClass: 'center' },
        // { key: "unit", name: "Unit/Div", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center', width: 100 },
        // { key: "email", name: "Email", filterable: true, filterRenderer: MultiSelectFilter, width: 200 },
        // { key: "tel1", name: "Tel 1", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
        // { key: "tel2", name: "Tel 2", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
    ];

    constructor(...args) {
        super(...args);

        let defaultColumnProperties = this.defaultColumnProperties;
        this.columns = this.columns.map(c => ({ ...defaultColumnProperties, ...c }));

        this.state = {
            // q: '',
            // user: null,
            users: [],
            modeAdd: false,
            code: '',
            name: '',
            loading: this.props.loading,
            // activePage: 1,
            // totalPages: 1,
            // totalUsers: 0,
            // itemsPerPage: 20,
            showMessageModal: false,
            messag: '',
            showDetail: false,
            showChangePassword: false,
            showEdit: false,
            showDeleteConfirm: false,
            newRecord: false,
        }
    }

    UNSAFE_componentWillMount() {
        // componentDidMount() {
        let u0 = this.context.users[0]
        this.setState({
            users: this.context.users,
            code: u0.code,
            name: u0.name,
        })
        console.log("----.users", this.context.users)
        // this.fetchTotalUsers();
        // this.fetchUsers();
        // this.fetchUsers()
    }

    ____fetchUsers = () => {
        util.fetchRpUsers().then(res => {
            this.setState({
                users: res.data
            })
        })
    }



    ___fetchTotalUsers() {
        fetch(apiUrl + 'rpuser/count', {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(response => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({
                    totalUsers: response.data,
                    totalPages: parseInt(response.data) / this.state.itemsPerPage
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    ___fetchUsers(q = '', page = 1) {

        let skip = (page - 1) * this.state.itemsPerPage;
        let limit = this.state.itemsPerPage;

        console.debug("fetchUsers", skip, limit);
        let url;
        if (q !== '' && q !== null) {
            url = apiUrl + 'rpuser/search/' + q;
        } else {
            url = apiUrl + 'rpuser?skip=' + skip + '&limit=' + limit;
        }

        fetch(url,
            {
                // fetch(apiUrl + 'user', {
                method: 'GET',
                params: { skip: skip, limit: limit },
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                }
            })
            .then(response => response.json())
            .then(jsonData => {
                // console.log(JSON.stringify(jsonData));
                this.setState({
                    users: jsonData.data,
                    activePage: page
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    handleChange = (e) => {
        console.log([e.target.id], e.target.value, e.target.checked, e.target.type)
        if (e.target.type === 'checkbox') {
            this.setState({ [e.target.id]: e.target.checked })
        } else {
            this.setState({ [e.target.id]: e.target.value })
        }
    }

    handleAdd = (e) => {
        let code = this.state.code;
        let name = this.state.name;
        let users = this.state.users;

        // Confirm that there's no existing code
        for (let i = 0; i < users.length; i++) {
            let u = users[i]
            if (code === u.code) {
                alert('มีรหัสผู้ใช้นี้อยู่แล้ว')
                return
            }
        }

        util.saveUser({
            code: code,
            name: name
        }).then(res => {
            alert(`เพิ่มข้อมูลผู้ใช้ใหม่แล้ว ${code} ${name}`)
            util.fetchRpUsers().then(res => {
                let users = res.data
                this.context.users = users
                this.setState({
                    users: users
                })
            })
        }).catch(err => {
            alert('เกิดความผิดพลาดในการเพิ่มข้อมูล\n' + err)
            console.error(err)
        })

        this.setState({
            _id: '',
            code: '',
            name: '',
            modeAdd: false,
        })
    }

    handleCancelAdd = (e) => {
        let u0 = this.state.users[0]
        this.setState({
            modeAdd: false,
            _id: '',
            code: u0.code,
            name: u0.name,
        })
    }

    handleUpdate = (e) => {
        let _id = this.state._id;
        let code = this.state.code;
        let name = this.state.name;
        let users = this.state.users;

        // console.log(_id)

        // Confirm that there's no existing code
        for (let i = 0; i < users.length; i++) {
            let u = users[i]
            if (code === u.code && _id !== u._id) {
                alert('มีรหัสผู้ใช้นี้อยู่แล้ว')
                return
            }
        }

        util.updateUser({
            _id: _id,
            code: code,
            name: name
        }).then(res => {
            alert(`แก้ไข้อมูลผู้ใช้ใหม่แล้ว ${code} ${name}`)
            util.fetchRpUsers().then(res => {
                let users = res.data
                this.context.users = users
                this.setState({
                    users: users
                })
            })
        }).catch(err => {
            alert('เกิดความผิดพลาดในการแก้ไขข้อมูล\n' + err)
            console.error(err)
        })

        // Leave updated data
        this.setState({
           modeAdd: false,
        })
    }

    handleRowClick = (id, user) => {
        console.log(user)
        if (user)
            this.setState({
                _id: user._id,
                code: user.code,
                name: user.name,
            })
    }

    handleDelete = (event) => {
        if (window.confirm(`ยืนยันว่าต้องการลบ ${this.state.name}`)) {
            let _id = this.state._id
            util.deleteUserById(_id).then(res => {
                alert("ลบแล้ว")
                util.fetchRpUsers().then(res => {
                    let users = res.data
                    this.context.users = users
                    let u0 = users[0]
                    this.setState({
                        users: users,
                        _id: u0._id,
                        code: u0.code,
                        name: u0.name,
                        modeAdd: false,
                    })
                })
            }).catch(err => {
                alert('เกิดความผิดพลาด\n' + err)
            })
        }
    }

    editHandler = (rowInx) => {
        this.showDetail(this.state.users[rowInx])
    }

    changePasswordHandler = (rowInx) => {
        this.changePassword(this.state.users[rowInx])
    }

    userToDelete = {};
    confirmDelete = (user) => {
        this.userToDelete = user;
        this.setState({
            showDeleteConfirm: true
        })
    }

    deleteHandler = (id) => {
        console.log(id);
        this.setState({ showDeleteConfirm: false },
            () => fetch(apiUrl + 'user', {
                method: 'DELETE',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                body: JSON.stringify({ id: id })
            })
                .then(response => response.json())
                .then(response => {
                    console.log('Delete Success:', JSON.stringify(response));
                    this.setState({
                        modalShowResult: true,
                        message: 'ลบข้อมูลผู้ใช้งาน แล้ว'
                    },
                        () => this.fetchUsers()
                    );
                })
                .catch(error => {
                    console.error('Error:', error);
                })
        );
    }


    showDetail = (v) => {
        // console.log(v);
        this.setState({
            showDetail: true,
            user: v
        });
    }



    closeDetail = (reload = true, afterCloseMessage = '') => {
        if (reload) {
            this.fetchUsers();
        }
        this.setState({
            showDetail: false,
            newRecord: false
        },
            () => {
                if (afterCloseMessage !== '') {
                    this.setState({
                        showMessageModal: true,
                        message: afterCloseMessage
                    });
                }
            });
    }

    changePassword = (v) => {
        this.setState({
            showChangePassword: true,
            user: v
        });
    }

    closeChangePassword = (reload = true, afterCloseMessage = '') => {
        if (reload) {
            this.fetchUsers();
        }
        this.setState({
            showDetail: false,
            showChangePassword: false
        },
            () => {
                if (afterCloseMessage !== '') {
                    this.setState({
                        showMessageModal: true,
                        message: afterCloseMessage
                    });
                }
            });
    }

    addHandler = () => {
        this.setState({
            modeAdd: true,
            code: '',
            name: ''
        });
    }

    searchChangeHandler = (e) => {
        this.setState({ q: e.target.value });
    }

    clearSearch = (e) => {
        let _this = this;
        this.setState(
            { q: '' },
            () => {
                _this.searchUsers();
            }
        );

    }

    ___searchUsers = () => {
        let q = this.state.q;
        console.log("Searching ", q);
        this.fetchUsers(q);
    }

    handleFilterChange = filter => {
        let filters = this.state.filters;
        const newFilters = { ...filters };
        if (filter.filterTerm) {
            newFilters[filter.column.key] = filter;
        } else {
            delete newFilters[filter.column.key];
        }
        return newFilters;
    };

    getValidFilterValues = (rows, columnId) => {
        return rows
            .map(r => r[columnId])
            .filter((item, i, a) => {
                return i === a.indexOf(item);
            });
    }


    getRows = (rows, filters) => {
        // console.log('filters', filters)
        return this.selectors.getRows({ rows, filters });
    }

    sortRows = (initialRows, sortColumn, sortDirection) => {
        console.log("sortRows")
        let rows = this.state.users;
        const comparer = (a, b) => {
            if (sortDirection === "ASC") {
                return a[sortColumn] > b[sortColumn] ? 1 : -1;
            } else if (sortDirection === "DESC") {
                return a[sortColumn] < b[sortColumn] ? 1 : -1;
            }
        };
        return sortDirection === "NONE" ? initialRows : [...rows].sort(comparer);
    }

    render() {
        let filteredRows = this.getRows(this.state.users, this.state.filters);

        if (this.props.loading) {
            return (
                <GridLoader
                    css={override}
                    // sizeUnit={"px"}
                    // size={8}
                    color={'#4A90E2'}
                    loading={true}
                />
            );

        } else {
            let title = this.state.modeAdd ? 'เพิ่มผู้ใช้งานใหม่' : 'แก้ไขข้อมูลผู้ใช้งาน';
            return (
                <>
                    <Container fluid>

                        {/* <Row>
                        <Col>
                            <InputGroup className="mb-3">
                                <FormControl
                                    placeholder="ค้นหาด้วยชื่อ"
                                    aria-label="ค้นหาด้วยชื่อ"
                                    aria-describedby="basic-addon2"
                                    value={this.state.q}
                                    onChange={this.searchChangeHandler}
                                    onKeyPress={event => {
                                        if (event.key === "Enter") {
                                            this.searchUsers();
                                        }
                                    }}
                                />
                                <InputGroup.Append>
                                    <Button variant="outline-secondary"
                                        onClick={this.searchUsers}>
                                        ค้นหา
                                </Button>
                                    <Button variant="outline-secondary"
                                        onClick={this.clearSearch}>
                                        <FaTimes />
                                    </Button>
                                </InputGroup.Append>
                            </InputGroup>

                        </Col>
                    </Row> */}
                        <Row style={{ minHeight: '80vh'}}>
                            <Col md={4} style={{ backgroundColor: '#ffffff' }}>
                                <ReactDataGrid
                                    columns={this.columns}
                                    rowGetter={i => filteredRows[i]}
                                    rowsCount={filteredRows.length}
                                    onRowClick={this.handleRowClick}
                                    // minWidth={1024}
                                    minHeight={'70vh'}
                                    onGridSort={(sortColumn, sortDirection) =>
                                        this.setState({
                                            users: this.sortRows(this.state.users, sortColumn, sortDirection)
                                        })
                                    }
                                    RowsContainer={ContextMenuTrigger}
                                    emptyRowsView={this.EmptyRowsView}
                                    toolbar={
                                        <Toolbar enableFilter={true}>
                                            {/* <ButtonGroup aria-label="Basic example">
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(0)}>
                                        View All
                                </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(1)}>
                                        A
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(2)}>
                                        B
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(3)}>
                                        C
                                    </Button>
                                </ButtonGroup> */}
                                        </Toolbar>
                                    }
                                    onAddFilter={filter => this.setState({ filters: this.handleFilterChange(filter) })}
                                    onClearFilters={() => this.setState({ filters: {} })}
                                    getValidFilterValues={columnKey => this.getValidFilterValues(this.state.users, columnKey)}

                                />
                            </Col>
                            <Col md={8} style={{ backgroundColor: '#ffffff' }}>
                                <Row>
                                    <Col>
                                        <h2>{title}</h2>
                                    </Col>
                                    <Col sm={4} style={{ textAlign: 'right' }}>
                                        <Button variant="success" onClick={this.addHandler}><FaPlus /> เพิ่มผู้ใช้งาน</Button>
                                    </Col>
                                </Row>
                                <Form disabled={this.viewMode}>

                                    <Form.Group>
                                        <Form.Label>Code</Form.Label>
                                        <Form.Control
                                            id="code"
                                            type="text"
                                            required
                                            onChange={this.handleChange}
                                            value={this.state.code} />
                                    </Form.Group>
                                    <Form.Group>
                                        <Form.Label>Name</Form.Label>
                                        <Form.Control
                                            id="name"
                                            type="text"
                                            required
                                            onChange={this.handleChange}
                                            value={this.state.name} />
                                    </Form.Group>
                                    {this.state.modeAdd && <Button variant="primary" onClick={this.handleAdd}>เพิ่มผู้ใช้</Button>}
                                    {this.state.modeAdd && <Button variant="secondary" onClick={this.handleCancelAdd}>ยกเลิก</Button>}
                                    {!this.state.modeAdd && <Button onClick={this.handleUpdate}>บันทึกข้อมูล</Button>}
                                    {!this.state.modeAdd && <Button variant="danger" onClick={this.handleDelete}>ลบผู้ใช้งาน</Button>}
                                </Form>
                            </Col>
                        </Row>

                    </Container>

                    {/* <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showDetail}
                        onHide={this.closeDetail}                    >
                        <Modal.Header closeButton>
                            <Modal.Title id="contained-modal-title-vcenter">
                                รายละเอียดผู้ใช้งาน
                    </Modal.Title>
                        </Modal.Header>
                        <Modal.Body>
                            <UserForm
                                newRecord={this.state.newRecord}
                                closeFormHandler={this.closeDetail}
                                data={this.state.user}
                            />
                        </Modal.Body>
                    </Modal>

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showChangePassword}
                        onHide={this.closeChangePassword}                    >
                        <Modal.Header closeButton>
                            <Modal.Title id="contained-modal-title-vcenter">
                                เปลี่ยนรหัสผ่าน
                    </Modal.Title>
                        </Modal.Header>
                        <Modal.Body>
                            <UserPasswordForm
                                closeFormHandler={this.closeChangePassword}
                                user={this.state.user}
                            />
                        </Modal.Body>
                    </Modal>

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showDeleteConfirm}
                        onHide={() => this.setState({ showDeleteConfirm: false })}
                    >

                        <Modal.Body>
                            ยืนยันลบข้อมูล {this.userToDelete.name}
                        </Modal.Body>
                        <Modal.Footer>
                            <Button variant="danger" onClick={() => this.deleteHandler(this.userToDelete._id)}>ลบ</Button>
                            <Button variant="outline-secondary" onClick={() => this.setState({ showDeleteConfirm: false })}>ยกเลิก</Button>
                        </Modal.Footer>
                    </Modal> */}

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showMessageModal}
                        onHide={() => this.setState({ showMessageModal: false })}
                    >
                        <Modal.Body>
                            {this.state.message}
                        </Modal.Body>
                        <Modal.Footer>
                            <Button variant="outline-secondary" onClick={() => this.setState({ showMessageModal: false })}>
                                ปิด
                            </Button>
                        </Modal.Footer>
                    </Modal>
                </>
            );
        }
    }
}
